#include <iostream>
#include <string>

class Vector2D {
private:
    double x;
    double y;

public:
    Vector2D(double x = 0, double y = 0) : x(x), y(y) {}

    void display() const {
        std::cout << "(" << x << ", " << y << ")";
    }

    // --- Operator Overloading (member functions) ---

    // Unary operator
    Vector2D operator-() const {
        return Vector2D(-x, -y);
    }

    // Binary operator
    Vector2D operator+(const Vector2D& other) const {
        return Vector2D(x + other.x, y + other.y);
    }

    Vector2D operator-(const Vector2D& other) const {
        return Vector2D(x - other.x, y - other.y);
    }

    Vector2D operator*(double scalar) const {
        return Vector2D(x * scalar, y * scalar);
    }

    // Comparison operators
    bool operator==(const Vector2D& other) const {
        return x == other.x && y == other.y;
    }

    bool operator!=(const Vector2D& other) const {
        return !(*this == other);
    }

    // Friend function for operator<< (stream output)
    friend std::ostream& operator<<(std::ostream& os, const Vector2D& v);

    // Friend function for operator+ with scalar first
    friend Vector2D operator*(double scalar, const Vector2D& v);

    // Getters
    double getX() const { return x; }
    double getY() const { return y; }
};

// --- Friend function implementations ---

std::ostream& operator<<(std::ostream& os, const Vector2D& v) {
    os << "(" << v.x << ", " << v.y << ")";
    return os;
}

Vector2D operator*(double scalar, const Vector2D& v) {
    return Vector2D(v.x * scalar, v.y * scalar);
}

// --- Class with friend functions ---
class Player {
private:
    std::string name;
    int health;
    int attackPower;
    Vector2D position;

public:
    Player(std::string n, int h, int a, Vector2D pos) 
        : name(n), health(h), attackPower(a), position(pos) {}

    void display() const {
        std::cout << name << " (HP: " << health << ", ATK: " << attackPower 
                  << ", Pos: " << position << ")" << std::endl;
    }

    // Friend functions
    friend void healPlayer(Player& p, int amount);
    friend void buffPlayer(Player& p, int amount);
    friend std::ostream& operator<<(std::ostream& os, const Player& p);
};

// --- Friend function implementations ---

void healPlayer(Player& p, int amount) {
    p.health += amount;
    std::cout << p.name << " healed by " << amount << "!" << std::endl;
}

void buffPlayer(Player& p, int amount) {
    p.attackPower += amount;
    std::cout << p.name << " buffed by " << amount << "!" << std::endl;
}

std::ostream& operator<<(std::ostream& os, const Player& p) {
    os << p.name << "[HP:" << p.health << ", ATK:" << p.attackPower 
       << ", Pos:" << p.position << "]";
    return os;
}

int main() {
    std::cout << "=== Operator Overloading & Friend Functions ===" << std::endl;

    // Vector operations
    Vector2D v1(3.0, 4.0);
    Vector2D v2(1.0, 2.0);

    std::cout << "v1: " << v1 << std::endl;
    std::cout << "v2: " << v2 << std::endl;
    std::cout << "v1 + v2 = " << (v1 + v2) << std::endl;
    std::cout << "v1 - v2 = " << (v1 - v2) << std::endl;
    std::cout << "v1 * 2 = " << (v1 * 2) << std::endl;
    std::cout << "3 * v1 = " << (3 * v1) << std::endl;
    std::cout << "-v1 = " << (-v1) << std::endl;
    std::cout << "v1 == v2? " << (v1 == v2) << std::endl;
    std::cout << "v1 != v2? " << (v1 != v2) << std::endl;

    // Player with friend functions
    std::cout << "\n=== Player with Friends ===" << std::endl;
    Player hero("Aragorn", 100, 20, Vector2D(5.0, 10.0));

    std::cout << "Hero: " << hero << std::endl;

    healPlayer(hero, 30);
    buffPlayer(hero, 10);

    std::cout << "After buff: " << hero << std::endl;

    // Using display method
    hero.display();

    return 0;
}

